parameters.jsCode:
// Extract the text from Gemini's response and parse it as JSON
const items = $input.all();
const results = [];

for (const item of items) {
  let text = '';

  // Handle both simplified and raw Gemini output formats
  if (typeof item.json.text === 'string') {
    text = item.json.text;
  } else if (item.json.content && item.json.content.parts) {
    text = item.json.content.parts.map(p => p.text).join('');
  } else if (typeof item.json === 'string') {
    text = item.json;
  } else {
    // Try to find text in any nested structure
    text = JSON.stringify(item.json);
  }

  // Clean up: remove markdown code fences if present
  text = text.replace(/```json\s*/g, '').replace(/```\s*/g, '').trim();

  let parsed;
  try {
    parsed = JSON.parse(text);
  } catch (e) {
    // If parsing fails, default to actionable to be safe
    parsed = {
      actionable: true,
      severity: 'medium',
      summary: 'AI analysis could not be parsed - forwarding alert for manual review',
      analysis: 'The AI response could not be parsed as JSON. Raw response: ' + text.substring(0, 500),
      recommendation: 'Review this alert manually in the Wazuh dashboard.'
    };
  }

  results.push({ json: parsed });
}

return results;

